    public static String getBonusWinPattern(int randomIndex, int bonusMultiplier) {
        StringBuilder bonusWinPattern = new StringBuilder();
        int randomBonusIndex = 0;
        switch (randomIndex) {
            case 0:
                randomBonusIndex = RandomUtil.getRandomInt(H1.length);
                bonusWinPattern.append(SlotEngineConstant.H1);
                break;
            case 1:
                randomBonusIndex = RandomUtil.getRandomInt(H2.length);
                bonusWinPattern.append(SlotEngineConstant.H2);
                break;
            case 2:
                randomBonusIndex = RandomUtil.getRandomInt(H3.length);
                bonusWinPattern.append(SlotEngineConstant.H3);
                break;
            case 3:
                randomBonusIndex = RandomUtil.getRandomInt(H12.length);
                bonusWinPattern.append(SlotEngineConstant.H1H2);
                break;
            case 4:
                randomBonusIndex = RandomUtil.getRandomInt(H13.length);
                bonusWinPattern.append(SlotEngineConstant.H1H3);
                break;
            case 5:
                randomBonusIndex = RandomUtil.getRandomInt(H23.length);
                bonusWinPattern.append(SlotEngineConstant.H2H3);
                break;
            case 6:
                randomBonusIndex = RandomUtil.getRandomInt(H123.length);
                bonusWinPattern.append(SlotEngineConstant.H1H2H3);
                break;
            case 7:
                randomBonusIndex = RandomUtil.getRandomInt(H1_WILD.length);
                bonusWinPattern.append(SlotEngineConstant.H1);
                break;
            case 8:
                randomBonusIndex = RandomUtil.getRandomInt(H2_WILD.length);
                bonusWinPattern.append(SlotEngineConstant.H2);
                break;
            case 9:
                randomBonusIndex = RandomUtil.getRandomInt(H3_WILD.length);
                bonusWinPattern.append(SlotEngineConstant.H3);
                break;
            case 10:
                randomBonusIndex = RandomUtil.getRandomInt(H12_WILD.length);
                bonusWinPattern.append(SlotEngineConstant.H1H2);
                break;
            case 11:
                randomBonusIndex = RandomUtil.getRandomInt(H13_WILD.length);
                bonusWinPattern.append(SlotEngineConstant.H1H3);
                break;
            case 12:
                randomBonusIndex = RandomUtil.getRandomInt(H23_WILD.length);
                bonusWinPattern.append(SlotEngineConstant.H2H3);
                break;
            case 13:
                randomBonusIndex = RandomUtil.getRandomInt(H123_WILD.length);
                bonusWinPattern.append(SlotEngineConstant.H1H2H3);
                break;
            default:
                break;
        }
        bonusWinPattern.append(bonusMultiplier);
        String randomStr = String.valueOf(randomBonusIndex);
        if (randomStr.length() == 1) {
            randomStr = "00" + randomStr;
        } else if (randomStr.length() == 2) {
            randomStr = "0" + randomStr;
        }
        bonusWinPattern.append(randomStr);
        return bonusWinPattern.toString();
    }

    public static int[] getCharactersResult(String bonusWinPattern, int[] allCharacters) {
        //前3位图标类型，第4位bonusMul,第5位后随机出现的pick characters
        int[] characterResult = null;
        if (bonusWinPattern.length() == SlotEngineConstant.BONUS_WIN_PATTER_LEN) {
            int iconType = Integer.parseInt(bonusWinPattern.substring(0, 3));
            int bonusMul = Integer.parseInt(bonusWinPattern.substring(3, 4));
            int randomIndex = Integer.parseInt(bonusWinPattern.substring(4));
            if (bonusMul > 1) {
                characterResult = getPickIcons(characterResult, iconType, randomIndex, H1_WILD, H2_WILD, H3_WILD, H12_WILD, H13_WILD, H23_WILD, H123_WILD);
            } else {
                characterResult = getPickIcons(characterResult, iconType, randomIndex, H1, H2, H3, H12, H13, H23, H123);
            }
        } else {
            log.error("BonusCharactersUtil.getCharactersResult..bonusWinPattern must be 7 characters,bonusWinPatternLen={} ", bonusWinPattern.length());
            throw new IllegalArgumentException("bonusWinPattern must be 7 characters");
        }
        if (characterResult != null) {
            List<Integer> tempList = StringUtil.array2IntegerList(characterResult);
            List<Integer> resultIconList = new ArrayList<>(tempList);
            List<Integer> remainIconList = getRemainIcon(resultIconList, allCharacters);
            resultIconList.addAll(remainIconList);
            return StringUtil.ListToIntegerArray(resultIconList);
        } else {
            return null;
        }

    }

    private static int[] getPickIcons(int[] characterResult, int coinType, int randomIndex, int[][] h1, int[][] h2, int[][] h3, int[][] h12, int[][] h13, int[][] h23, int[][] h123) {
        switch (coinType) {
            case SlotEngineConstant.H1:
                characterResult = h1[randomIndex];
                break;
            case SlotEngineConstant.H2:
                characterResult = h2[randomIndex];
                break;
            case SlotEngineConstant.H3:
                characterResult = h3[randomIndex];
                break;
            case SlotEngineConstant.H1H2:
                characterResult = h12[randomIndex];
                break;
            case SlotEngineConstant.H1H3:
                characterResult = h13[randomIndex];
                break;
            case SlotEngineConstant.H2H3:
                characterResult = h23[randomIndex];
                break;
            case SlotEngineConstant.H1H2H3:
                characterResult = h123[randomIndex];
                break;
            default:
                break;
        }
        return characterResult;
    }

