    private static int[] generateNormalMode(int randomIndex, boolean is2xMode, int[] allCharacters) {
        int[] result = new int[allCharacters.length];
        if (is2xMode) {  //contain wild
            switch (randomIndex) {
                case 7:   //match H1
                    result = computeMatchH1(true, allCharacters);
                    break;
                case 8:   //match H2
                    result = computeMatchH2(true, allCharacters);
                    break;
                case 9:   //match H3
                    result = computeMatchH3(true, allCharacters);
                    break;
                case 10: //match H1H2
                    result = computeMatchH1H2(allCharacters);
                    break;
                case 11: //match H1H3
                    result = computeMatchH1H3(allCharacters);
                    break;
                case 12:  //match H2H3
                    result = computeMatchH2H3(allCharacters);
                    break;
                case 13:  //match H1H2H3
                    result = computeMatchH1H2H3(allCharacters);
                    break;
                default:
                    break;
            }
        } else {
            int weightIndex = RandomUtil.getRandomIndexFromArrayWithWeight(new int[]{9, 1});
            boolean isWild = weightIndex == 1;
            switch (randomIndex) {
                case 0:   //match H1
                    result = computeMatchH1(isWild, allCharacters);
                    break;
                case 1:   //match H2
                    result = computeMatchH2(isWild, allCharacters);
                    break;
                case 2:   //match H3
                    result = computeMatchH3(isWild, allCharacters);
                    break;
                case 3:
                    result = computeMatchH1H2(allCharacters);
                    break;
                case 4:
                    result = computeMatchH1H3(allCharacters);
                    break;
                case 5:
                    result = computeMatchH2H3(allCharacters);
                    break;
                case 6:
                    result = computeMatchH1H2H3(allCharacters);
                    break;
                default:
                    break;
            }

        }
        return result;
    }

    private static int[] computeMatchH1H2H3(int[] allCharacters) {
        int[][] preResultPick = new int[][]{{4, 4}, {1, 2, 3, 4}, {1, 1, 2, 2, 3, 3}};
        List<Integer> resultIconList = getResultList(preResultPick, 4, allCharacters);
        return StringUtil.ListToIntegerArray(resultIconList);
    }

    private static int[] computeMatchH2H3(int[] allCharacters) {
        List<Integer> resultIconList;
        int endClick = 5 + RandomUtil.getInternalRandom(2);
        int[][] preResultPick = null;
        if (endClick == 6) {
            preResultPick = new int[][]{{2, 2, 3, 3, 1}};
        } else {
            preResultPick = new int[][]{{2, 2, 3, 3}};
        }
        resultIconList = getResultList(preResultPick, 4, allCharacters);
        return StringUtil.ListToIntegerArray(resultIconList);
    }

    private static int[] computeMatchH1H3(int[] allCharacters) {
        List<Integer> resultIconList;
        int endClick = 5 + RandomUtil.getInternalRandom(2);
        int[][] preResultPick = null;
        if (endClick == 6) {
            preResultPick = new int[][]{{1, 1, 3, 3, 2}};
        } else {
            preResultPick = new int[][]{{1, 1, 3, 3}};
        }
        resultIconList = getResultList(preResultPick, 4, allCharacters);
        return StringUtil.ListToIntegerArray(resultIconList);
    }

    private static int[] computeMatchH1H2(int[] allCharacters) {
        List<Integer> resultIconList;
        int endClick = 5 + RandomUtil.getInternalRandom(2);
        int[][] preResultPick = null;
        if (endClick == 6) {
            preResultPick = new int[][]{{1, 1, 2, 2, 3}};
        } else {
            preResultPick = new int[][]{{1, 1, 2, 2}};
        }
        resultIconList = getResultList(preResultPick, 4, allCharacters);
        return StringUtil.ListToIntegerArray(resultIconList);
    }

    private static int[] computeMatchH3(boolean isWild, int[] allCharacters) {
        List<Integer> resultIconList;
        int endClick = 5 + RandomUtil.getInternalRandom(3);
        int[][] preResultPick = null;
        if (!isWild) {
            //endClick 5次结束最后一次是H1
            switch (endClick) {
                case 5:
                    preResultPick = new int[][]{{3, 3, 1, 2}, {3, 3, 1, 1}, {3, 3, 2, 2}, {3, 4, 1, 2}};
                    break;
                case 6:
                    preResultPick = new int[][]{{3, 3, 1, 1, 2}, {3, 3, 2, 2, 1}};
                    break;
                case 7:
                    preResultPick = new int[][]{{1, 1, 2, 2, 3, 3}};
                    break;
                default:
                    preResultPick = new int[][]{{3, 3, 1, 2}, {3, 3, 1, 1}, {3, 3, 2, 2}, {3, 4, 1, 2}};
                    break;
            }
            resultIconList = getResultList(preResultPick, 3, allCharacters);
        } else {
            //contain wild only pick 5
            int randomIndex = RandomUtil.getInternalRandom(2);
            if (randomIndex == 0) {
                preResultPick = new int[][]{{3, 3, 1, 2}};
                resultIconList = getResultList(preResultPick, 4, allCharacters);
            } else {
                preResultPick = new int[][]{{3, 4, 1, 2}};
                resultIconList = getResultList(preResultPick, 3, allCharacters);
            }
        }
        return StringUtil.ListToIntegerArray(resultIconList);
    }

    private static int[] computeMatchH2(boolean isWild, int[] allCharacters) {
        List<Integer> resultIconList = new ArrayList<>();
        int endClick = 5 + RandomUtil.getInternalRandom(3);
        int[][] preResultPick = null;
        if (!isWild) {
            //endClick 5次结束最后一次是H1
            switch (endClick) {
                case 5:
                    preResultPick = new int[][]{{2, 2, 1, 3}, {2, 2, 1, 1}, {2, 2, 3, 3}, {2, 4, 1, 3}};
                    break;
                case 6:
                    preResultPick = new int[][]{{2, 2, 1, 1, 3}, {2, 2, 3, 3, 1}};
                    break;
                case 7:
                    preResultPick = new int[][]{{1, 1, 2, 2, 3, 3}};
                    break;
                default:
                    preResultPick = new int[][]{{2, 2, 1, 3}, {2, 2, 1, 1}, {2, 2, 3, 3}, {2, 4, 1, 3}};
                    break;
            }
            resultIconList = getResultList(preResultPick, 2, allCharacters);
        } else {
            //contain wild only pick 5
            int randomIndex = RandomUtil.getInternalRandom(2);
            if (randomIndex == 0) {
                preResultPick = new int[][]{{2, 2, 1, 3}};
                resultIconList = getResultList(preResultPick, 4, allCharacters);
            } else {
                preResultPick = new int[][]{{2, 4, 1, 3}};
                resultIconList = getResultList(preResultPick, 2, allCharacters);
            }
        }
        return StringUtil.ListToIntegerArray(resultIconList);
    }

    private static int[] computeMatchH1(boolean isWild, int[] allCharacters) {
        List<Integer> resultIconList = new ArrayList<>();
        int endClick = 5 + RandomUtil.getInternalRandom(3);
        int[][] preResultPick = null;
        if (!isWild) {
            //endClick 5次结束最后一次是H1
            switch (endClick) {
                case 5:
                    preResultPick = new int[][]{{1, 1, 2, 3}, {1, 1, 2, 2}, {1, 1, 3, 3}, {1, 4, 2, 3}};
                    break;
                case 6:
                    preResultPick = new int[][]{{1, 1, 2, 2, 3}, {1, 1, 3, 3, 2}};
                    break;
                case 7:
                    preResultPick = new int[][]{{1, 1, 2, 2, 3, 3}};
                    break;
                default:
                    preResultPick = new int[][]{{1, 1, 2, 3}, {1, 1, 2, 2}, {1, 1, 3, 3}, {1, 4, 2, 3}};
                    break;
            }
            resultIconList = getResultList(preResultPick, 1, allCharacters);
        } else {
            //contain wild only pick 5
            int randomIndex = RandomUtil.getInternalRandom(2);
            if (randomIndex == 0) {
                preResultPick = new int[][]{{1, 1, 2, 3}};
                resultIconList = getResultList(preResultPick, 4, allCharacters);
            } else {
                preResultPick = new int[][]{{1, 4, 2, 3}};
                resultIconList = getResultList(preResultPick, 1, allCharacters);
            }
        }
        return StringUtil.ListToIntegerArray(resultIconList);
    }

    private static List<Integer> getResultList(int[][] preMatchPick, int iconIndex, int[] allCharacters) {
        int randomEndIndex = RandomUtil.getInternalRandom(preMatchPick.length);
        List<Integer> tempList = StringUtil.array2IntegerList(preMatchPick[randomEndIndex]);
        Collections.shuffle(tempList);
        List<Integer> resultIconList = new ArrayList<>(tempList);
        resultIconList.add(iconIndex);
        //List<Integer> remainIconList = getRemainIcon(resultIconList, allCharacters);
        //resultIconList.addAll(remainIconList);
        return resultIconList;
    }

    /**
     * 找到匹配图片后剩余图标
     *
     * @param resultIconList
     * @param allCharacters
     * @return
     */
    private static List<Integer> getRemainIcon(List<Integer> resultIconList, int[] allCharacters) {
        List<Integer> pickIconList = new ArrayList<>(resultIconList);
        List<Integer> remainIconList = new ArrayList<>();
        for (int icon : allCharacters) {
            remainIconList.add(icon);
        }
        for (int resultIcon : pickIconList) {
            Iterator<Integer> iterator = remainIconList.iterator();
            while (iterator.hasNext()) {
                if (iterator.next() == (resultIcon % 1000)) {
                    iterator.remove();
                    break;
                }
            }
        }
        Collections.shuffle(remainIconList);
        return remainIconList;
    }


